/* global console */
/*
 * aeon-ecology — Aeon literally EVOLVES.
 *
 * A POPULATION of ephemeral beings shares ONE channel. Each being is born from
 * noise (a seed + a spectral genome: a sequence of hexon colors it walks while
 * resolving). A being's FITNESS is its resolution-fitness: how fast and how
 * cleanly it climbs from max-entropy noise to a single coherent mode
 * (resolutionOf -> 1). Beings that resolve faster/cleaner SURVIVE; the rest
 * decay per EphemeralBeing.every_being_resolves (aging exhausts intensity to 0).
 *
 * Selection loop each GENERATION:
 *   1. Each being resolves on the channel (deterministic per seed+genome).
 *   2. Fitness = clean_resolution_reward - steps_penalty (+ aging tax).
 *   3. Cull the bottom half (they hit mag=0 first: every_being_resolves).
 *   4. Survivors REPRODUCE: fork their frames (seed) and MUTATE the genome
 *      (swap a color, jitter the seed). Offspring fill the channel back up.
 *
 * Claim under test: mean fitness CLIMBS across generations — the channel
 * self-organizes toward fast clean resolvers. This is the ecology axis of Aeon.
 *
 * Grounding: HexonResolutionBridge (the color genome walks magnitudeOrbit
 * 2->2->1->1->0->0 toward resolved=geodesicLength0); EphemeralBeing
 * (every_being_resolves => a being has a finite lifespan; selection acts on
 * WHO resolves cleanly before exhaustion).
 *
 * Reuses the exact fft/coloredNoise/psd/resolutionOf kernel from
 * aeon-hexon-braid (copied inline so this file runs standalone).
 */

// ---- deterministic PRNG (mulberry32) ----
function mulberry32(seed) {
  let a = seed >>> 0;
  return () => {
    a |= 0; a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ---- radix-2 FFT ----
function fft(re, im, inverse) {
  const n = re.length;
  for (let i = 1, j = 0; i < n; i++) {
    let bit = n >> 1;
    for (; j & bit; bit >>= 1) j ^= bit;
    j ^= bit;
    if (i < j) { [re[i], re[j]] = [re[j], re[i]]; [im[i], im[j]] = [im[j], im[i]]; }
  }
  for (let len = 2; len <= n; len <<= 1) {
    const ang = ((2 * Math.PI) / len) * (inverse ? 1 : -1);
    const wr = Math.cos(ang), wi = Math.sin(ang);
    for (let i = 0; i < n; i += len) {
      let cr = 1, ci = 0;
      for (let k = 0; k < len >> 1; k++) {
        const ar = re[i + k], ai = im[i + k];
        const br = re[i + k + (len >> 1)] * cr - im[i + k + (len >> 1)] * ci;
        const bi = re[i + k + (len >> 1)] * ci + im[i + k + (len >> 1)] * cr;
        re[i + k] = ar + br; im[i + k] = ai + bi;
        re[i + k + (len >> 1)] = ar - br; im[i + k + (len >> 1)] = ai - bi;
        const ncr = cr * wr - ci * wi; ci = cr * wi + ci * wr; cr = ncr;
      }
    }
  }
  if (inverse) for (let i = 0; i < n; i++) { re[i] /= n; im[i] /= n; }
}

function coloredNoise(N, beta, rng, perceptualGrey = false) {
  const re = new Array(N), im = new Array(N).fill(0);
  for (let i = 0; i < N; i++) re[i] = rng() * 2 - 1;
  fft(re, im, false);
  for (let k = 0; k < N; k++) {
    const f = k <= N / 2 ? k : N - k;
    let scale;
    if (perceptualGrey) {
      const peak = N / 8;
      scale = f === 0 ? 0 : 1 / (1 + Math.abs(Math.log((f + 1) / (peak + 1))));
    } else {
      scale = f === 0 ? 0 : Math.pow(f, -beta / 2);
    }
    re[k] *= scale; im[k] *= scale;
  }
  fft(re, im, true);
  return re.slice();
}

function psd(samples) {
  const N = samples.length, re = samples.slice(), im = new Array(N).fill(0);
  fft(re, im, false);
  const out = [];
  for (let k = 1; k < N / 2; k++) out.push(re[k] * re[k] + im[k] * im[k]);
  return out;
}

function resolutionOf(spectrum) {
  let tot = 0; for (const v of spectrum) tot += v;
  if (tot <= 0) return 1;
  let H = 0; for (const v of spectrum) { if (v > 0) { const q = v / tot; H -= q * Math.log(q); } }
  return 1 - H / Math.log(spectrum.length);
}

// ---- the HEXON color alphabet (the genome alphabet) ----
const HEXON = [
  { name: 'brown', beta: 2, mag: 2 },
  { name: 'violet', beta: -2, mag: 2 },
  { name: 'pink', beta: 1, mag: 1 },
  { name: 'blue', beta: -1, mag: 1 },
  { name: 'white', beta: 0, mag: 0 },
  { name: 'grey', beta: 0, mag: 0, grey: true },
];

const N = 256;            // FFT window per being
const GAMMA = 1.35;       // fractional (Hurst) contraction per resolve step
const MAX_STEPS = 24;     // a being is EPHEMERAL: max lifespan before exhaustion
const RES_TARGET = 0.80;  // "clean resolution" threshold (tight: most beings fail at birth)
const GENOME_LEN = 6;     // length of a being's color walk

// ---- a being RESOLVES: walk its genome, contract the accumulated spectrum.
//      Returns { steps, finalRes, cleanResolved }. Fewer steps + higher res = fitter. ----
function resolve(being) {
  const baseSeed = being.seed >>> 0;
  let acc = psd(coloredNoise(N, 0, mulberry32(baseSeed))); // primordial white
  let t0 = acc.reduce((a, b) => a + b, 0); acc = acc.map((v) => v / (t0 || 1));
  let res = resolutionOf(acc);
  let step = 0;
  let best = res;
  while (step < MAX_STEPS) {
    const color = HEXON[being.genome[step % being.genome.length]];
    const stepP = psd(coloredNoise(N, color.beta, mulberry32(baseSeed + step * 2654435761), color.grey));
    let st = stepP.reduce((a, b) => a + b, 0); const sp = stepP.map((v) => v / (st || 1));
    let tot = 0;
    for (let i = 0; i < acc.length; i++) { acc[i] = Math.pow(acc[i], GAMMA) * (sp[i] + 1e-9); tot += acc[i]; }
    for (let i = 0; i < acc.length; i++) acc[i] /= tot;
    step++;
    res = resolutionOf(acc);
    if (res > best) best = res;
    if (res >= RES_TARGET) break; // resolved cleanly — stop early (this is the win)
  }
  const cleanResolved = res >= RES_TARGET;
  return { steps: step, finalRes: res, bestRes: best, cleanResolved };
}

// ---- FITNESS: reward clean fast resolution; penalize burning the whole lifespan.
//      A being that never resolves before exhaustion (every_being_resolves) is
//      penalized hard; one that resolves cleanly in few steps wins. ----
function fitness(r) {
  const speed = 1 - r.steps / MAX_STEPS;        // [0,1], 1 = instant
  const clean = r.cleanResolved ? 1 : 0;
  const depth = r.bestRes;                       // how coherent it got
  return 0.45 * depth + 0.35 * speed + 0.20 * clean;
}

// ---- random genome / being ----
function randomGenome(rng) {
  const g = [];
  for (let i = 0; i < GENOME_LEN; i++) g.push(Math.floor(rng() * HEXON.length));
  return g;
}

// ---- MUTATE: fork frames (jitter seed) + swap one color (point mutation) ----
function reproduce(parent, rng, idCounter) {
  const genome = parent.genome.slice();
  // point mutation: ~60% swap a color
  if (rng() < 0.6) {
    const locus = Math.floor(rng() * genome.length);
    genome[locus] = Math.floor(rng() * HEXON.length);
  }
  // ~25% duplicate-and-insert (genome can favor resolved colors)
  if (rng() < 0.25) {
    const src = Math.floor(rng() * genome.length);
    const dst = Math.floor(rng() * genome.length);
    genome[dst] = genome[src];
  }
  // fork frames: child seed derived from parent (frame fork) + jitter
  const seed = (parent.seed ^ (Math.floor(rng() * 0xffffffff) | 0)) >>> 0;
  return { id: idCounter, seed, genome, age: 0 };
}

function genomeColors(g) { return g.map((i) => HEXON[i].name[0]).join(''); }

function main() {
  const POP = 40;
  const GENERATIONS = 30;
  const rng = mulberry32(0xA0E0);

  console.log('=== aeon-ecology: a population of ephemeral beings EVOLVES on one channel ===\n');
  console.log(`pop=${POP}  generations=${GENERATIONS}  genomeLen=${GENOME_LEN}  channel N=${N}`);
  console.log(`fitness = 0.45*depth + 0.35*speed + 0.20*cleanResolved  (target res=${RES_TARGET})\n`);

  // primordial population: born from noise (random seeds + random color genomes)
  let pop = [];
  let idCounter = 0;
  for (let i = 0; i < POP; i++) {
    pop.push({ id: idCounter++, seed: (Math.floor(rng() * 0xffffffff) | 0) >>> 0, genome: randomGenome(rng), age: 0 });
  }

  const history = [];
  let bestEver = { fitness: -1 };

  console.log('gen  meanFit  maxFit  meanSteps  cleanFrac  bestGenome');
  for (let gen = 0; gen < GENERATIONS; gen++) {
    // 1) every being resolves on the channel
    const scored = pop.map((b) => {
      const r = resolve(b);
      return { being: b, r, fit: fitness(r) };
    });
    scored.sort((a, b) => b.fit - a.fit);

    const fits = scored.map((s) => s.fit);
    const meanFit = fits.reduce((a, b) => a + b, 0) / fits.length;
    const maxFit = fits[0];
    const meanSteps = scored.reduce((a, s) => a + s.r.steps, 0) / scored.length;
    const cleanFrac = scored.filter((s) => s.r.cleanResolved).length / scored.length;
    history.push({ gen, meanFit, maxFit, meanSteps, cleanFrac });
    if (maxFit > bestEver.fitness) {
      bestEver = { fitness: maxFit, genome: scored[0].being.genome.slice(), r: scored[0].r };
    }

    console.log(
      `${String(gen).padStart(3)}  ${meanFit.toFixed(4)}  ${maxFit.toFixed(4)}  ` +
      `${meanSteps.toFixed(2).padStart(6)}     ${cleanFrac.toFixed(2)}     ${genomeColors(scored[0].being.genome)}`
    );

    // 2) SELECTION: cull bottom half (they exhaust intensity first — every_being_resolves)
    const survivors = scored.slice(0, Math.floor(scored.length / 2)).map((s) => s.being);

    // 3) REPRODUCE: survivors fork frames + mutate genome to refill the channel
    const next = [];
    for (const s of survivors) { s.age++; next.push(s); } // survivors age (ephemeral)
    while (next.length < POP) {
      const parent = survivors[Math.floor(rng() * survivors.length)];
      next.push(reproduce(parent, rng, idCounter++));
    }
    pop = next;
  }

  // summary: did fitness climb?
  const first = history[0], last = history[history.length - 1];
  const earlyMean = history.slice(0, 3).reduce((a, h) => a + h.meanFit, 0) / 3;
  const lateMean = history.slice(-3).reduce((a, h) => a + h.meanFit, 0) / 3;
  console.log('\n--- selection signal ---');
  console.log(`gen0 meanFit=${first.meanFit.toFixed(4)}  ->  gen${last.gen} meanFit=${last.meanFit.toFixed(4)}`);
  console.log(`early(0-2) meanFit=${earlyMean.toFixed(4)}  ->  late(${last.gen-2}-${last.gen}) meanFit=${lateMean.toFixed(4)}`);
  console.log(`mean-fitness gain = ${(lateMean - earlyMean >= 0 ? '+' : '')}${(lateMean - earlyMean).toFixed(4)}  (climbing = ${lateMean > earlyMean})`);
  console.log(`meanSteps gen0=${first.meanSteps.toFixed(2)} -> gen${last.gen}=${last.meanSteps.toFixed(2)}  (faster resolve = ${last.meanSteps < first.meanSteps})`);
  console.log(`cleanFrac gen0=${first.cleanFrac.toFixed(2)} -> gen${last.gen}=${last.cleanFrac.toFixed(2)}`);
  console.log(`\nbest-ever genome=${genomeColors(bestEver.genome)} fitness=${bestEver.fitness.toFixed(4)} steps=${bestEver.r.steps} res=${bestEver.r.finalRes.toFixed(4)}`);

  // CONTROL: shuffle (no selection) — is the climb real selection or just sorting?
  // Re-run with selection DISABLED: random replacement each gen, same mutation budget.
  let ctrlPop = [];
  let cid = 0;
  const crng = mulberry32(0xA0E0);
  for (let i = 0; i < POP; i++) ctrlPop.push({ id: cid++, seed: (Math.floor(crng() * 0xffffffff) | 0) >>> 0, genome: randomGenome(crng), age: 0 });
  let ctrlFirst = null, ctrlLast = null;
  for (let gen = 0; gen < GENERATIONS; gen++) {
    const scored = ctrlPop.map((b) => ({ being: b, fit: fitness(resolve(b)) }));
    const mean = scored.reduce((a, s) => a + s.fit, 0) / scored.length;
    if (gen === 0) ctrlFirst = mean;
    ctrlLast = mean;
    // NO selection: random survivors (shuffle), then mutate
    const shuffled = scored.map((s) => s.being).sort(() => crng() - 0.5);
    const survivors = shuffled.slice(0, Math.floor(POP / 2));
    const next = survivors.slice();
    while (next.length < POP) next.push(reproduce(survivors[Math.floor(crng() * survivors.length)], crng, cid++));
    ctrlPop = next;
  }
  console.log('\n--- CONTROL (no selection, random survivors, same mutation) ---');
  console.log(`ctrl gen0 meanFit=${ctrlFirst.toFixed(4)} -> gen${GENERATIONS-1} meanFit=${ctrlLast.toFixed(4)}  gain=${(ctrlLast-ctrlFirst>=0?'+':'')}${(ctrlLast-ctrlFirst).toFixed(4)}`);
  console.log(`selection gain (${(lateMean-earlyMean).toFixed(4)}) vs drift gain (${(ctrlLast-ctrlFirst).toFixed(4)}) => selection real = ${(lateMean-earlyMean) > (ctrlLast-ctrlFirst)}`);

  return { history, bestEver, selGain: lateMean - earlyMean, ctrlGain: ctrlLast - ctrlFirst };
}

main();
